function active$FormSOAddress(f) {f.add_onResponseComplete(on$FormSOAddress$ResponseComplete);}
function close$FormSOAddress(f) {try {f.remove_onResponseComplete(on$FormSOAddress$ResponseComplete)} catch (ex) {}}
function on$FormSOAddress$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_dc');
      break;
    default:
      break;
  }
}

      &ScriptIrregular;
